1	package service
2	
3	import (
4		"context"
5		"crypto/hmac"
6		"crypto/sha256"
7		"encoding/hex"
8		"encoding/json"
9		"fmt"
10		"log/slog"
11		"time"
12	
13		"github.com/jackc/pgx/v5"
14		"github.com/jackc/pgx/v5/pgxpool"
15	
16		"github.com/ravencloak-org/Raven/internal/db"
17		"github.com/ravencloak-org/Raven/internal/hyperswitch"
18		"github.com/ravencloak-org/Raven/internal/model"
19		"github.com/ravencloak-org/Raven/pkg/apierror"
20	)
21	
22	// BillingRepository defines the persistence interface for billing operations.
23	type BillingRepository interface {
24		CreateSubscription(ctx context.Context, tx pgx.Tx, sub *model.Subscription) (*model.Subscription, error)
25		GetSubscriptionByID(ctx context.Context, tx pgx.Tx, orgID, subscriptionID string) (*model.Subscription, error)
26		GetSubscriptionByHyperswitchID(ctx context.Context, tx pgx.Tx, hsID string) (*model.Subscription, error)
27		GetActiveSubscription(ctx context.Context, tx pgx.Tx, orgID string) (*model.Subscription, error)
28		UpdateSubscriptionStatus(ctx context.Context, tx pgx.Tx, orgID, subscriptionID string, status model.SubscriptionStatus) (*model.Subscription, error)
29		ExtendSubscriptionPeriod(ctx context.Context, tx pgx.Tx, hyperswitchID string) (*model.Subscription, error)
30		InsertPaymentEvent(ctx context.Context, tx pgx.Tx, orgID, eventType, paymentID, status string, rawPayload []byte) (bool, error)
31	}
32	
33	// HyperswitchClient defines the interface for Hyperswitch API operations.
34	type HyperswitchClient interface {
35		CreatePayment(ctx context.Context, req *hyperswitch.CreatePaymentRequest) (*hyperswitch.PaymentResponse, error)
36		CancelPayment(ctx context.Context, paymentID string) error
37	}
38	
39	// BillingService contains business logic for subscription and payment management
40	// via the Hyperswitch payment orchestration platform.
41	type BillingService struct {
42		repo          BillingRepository
43		pool          *pgxpool.Pool
44		hsClient      HyperswitchClient
45		webhookSecret string
46		plans         map[string]model.Plan
47	}
48	
49	// NewBillingService creates a new BillingService.
50	func NewBillingService(repo BillingRepository, pool *pgxpool.Pool, hsClient HyperswitchClient, webhookSecret string) *BillingService {
51		plans := make(map[string]model.Plan)
52		for _, p := range model.DefaultPlans() {
53			plans[p.ID] = p
54		}
55		return &BillingService{
56			repo:          repo,
57			pool:          pool,
58			hsClient:      hsClient,
59			webhookSecret: webhookSecret,
60			plans:         plans,
61		}
62	}
63	
64	// GetPlans returns the available billing plans.
65	func (s *BillingService) GetPlans() []model.Plan {
66		return model.DefaultPlans()
67	}
68	
69	// GetPlanByID returns a plan by ID, or an error if not found.
70	func (s *BillingService) GetPlanByID(planID string) (*model.Plan, error) {
71		p, ok := s.plans[planID]
72		if !ok {
73			return nil, apierror.NewNotFound("plan not found: " + planID)
74		}
75		return &p, nil
76	}
77	
78	// CreateSubscription creates a new subscription for the given organisation.
79	// For paid plans, it calls Hyperswitch to set up a recurring payment via Razorpay.
80	func (s *BillingService) CreateSubscription(ctx context.Context, orgID string, req model.CreateSubscriptionRequest) (*model.Subscription, error) {
81		plan, err := s.GetPlanByID(req.PlanID)
82		if err != nil {
83			return nil, err
84		}
85	
86		now := time.Now().UTC()
87	
88		// Check if org already has an active subscription.
89		var existing *model.Subscription
90		err = db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
91			var e error
92			existing, e = s.repo.GetActiveSubscription(ctx, tx, orgID)
93			return e
94		})
95		if err != nil {
96			slog.ErrorContext(ctx, "failed to check existing subscription", "error", err)
97			return nil, apierror.NewInternal("failed to check existing subscription")
98		}
99		if existing != nil {
100			return nil, apierror.NewConflict("organisation already has an active subscription: " + existing.ID)
101		}
102	
103		// For the free plan, no payment orchestration is needed.
104		if plan.Tier == model.PlanTierFree {
105			sub := &model.Subscription{
106				OrgID:              orgID,
107				PlanID:             plan.ID,
108				Status:             model.SubscriptionStatusActive,
109				CurrentPeriodStart: now,
110				CurrentPeriodEnd:   now.AddDate(0, 1, 0),
111			}
112	
113			var result *model.Subscription
114			err = db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
115				var e error
116				result, e = s.repo.CreateSubscription(ctx, tx, sub)
117				return e
118			})
119			if err != nil {
120				slog.ErrorContext(ctx, "failed to persist free subscription", "error", err)
121				return nil, apierror.NewInternal("failed to persist free subscription")
122			}
123			return result, nil
124		}
125	
126		// Paid plan: create a payment via Hyperswitch with Razorpay as the connector.
127		hsResp, err := s.hsClient.CreatePayment(ctx, &hyperswitch.CreatePaymentRequest{
128			Amount:           plan.PriceMonthly,
129			Currency:         "USD",
130			CustomerID:       orgID,
131			SetupFutureUsage: "off_session",
132			Metadata: map[string]string{
133				"plan_id": plan.ID,
134				"org_id":  orgID,
135			},
136		})
137		if err != nil {
138			slog.ErrorContext(ctx, "failed to create Hyperswitch payment", "error", err)
139			return nil, apierror.NewInternal("failed to create Hyperswitch payment")
140		}
141	
142		sub := &model.Subscription{
143			OrgID:                     orgID,
144			PlanID:                    plan.ID,
145			Status:                    model.SubscriptionStatusActive,
146			HyperswitchSubscriptionID: hsResp.PaymentID,
147			CurrentPeriodStart:        now,
148			CurrentPeriodEnd:          now.AddDate(0, 1, 0),
149		}
150	
151		var result *model.Subscription
152		err = db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
153			var e error
154			result, e = s.repo.CreateSubscription(ctx, tx, sub)
155			return e
156		})
157		if err != nil {
158			slog.ErrorContext(ctx, "failed to persist subscription", "error", err)
159			return nil, apierror.NewInternal("failed to persist subscription")
160		}
161		return result, nil
162	}
163	
164	// CancelSubscription cancels the subscription for the given organisation.
165	func (s *BillingService) CancelSubscription(ctx context.Context, orgID string, subscriptionID string) error {
166		var sub *model.Subscription
167		err := db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
168			var e error
169			sub, e = s.repo.GetSubscriptionByID(ctx, tx, orgID, subscriptionID)
170			return e
171		})
172		if err != nil {
173			slog.ErrorContext(ctx, "failed to look up subscription", "error", err)
174			return apierror.NewInternal("failed to look up subscription")
175		}
176		if sub == nil {
177			return apierror.NewNotFound("subscription not found")
178		}
179	
180		// Cancel on Hyperswitch if there is a linked payment.
181		if sub.HyperswitchSubscriptionID != "" {
182			if err := s.hsClient.CancelPayment(ctx, sub.HyperswitchSubscriptionID); err != nil {
183				slog.ErrorContext(ctx, "failed to cancel Hyperswitch payment", "error", err)
184				return apierror.NewInternal("failed to cancel Hyperswitch payment")
185			}
186		}
187	
188		// Update status in DB.
189		return db.WithOrgID(ctx, s.pool, orgID, func(tx pgx.Tx) error {
190			_, e := s.repo.UpdateSubscriptionStatus(ctx, tx, orgID, subscriptionID, model.SubscriptionStatusCanceled)
191			return e
192		})
193	}
194	
195	// CreatePaymentIntent creates a one-off payment intent via Hyperswitch.
196	func (s *BillingService) CreatePaymentIntent(ctx context.Context, orgID string, req model.CreatePaymentIntentRequest) (*model.PaymentIntent, error) {
197		hsResp, err := s.hsClient.CreatePayment(ctx, &hyperswitch.CreatePaymentRequest{
198			Amount:     req.Amount,
199			Currency:   req.Currency,
200			CustomerID: orgID,
201		})
202		if err != nil {
203			slog.ErrorContext(ctx, "failed to create Hyperswitch payment", "error", err)
204			return nil, apierror.NewInternal("failed to create Hyperswitch payment")
205		}
206	
207		now := time.Now().UTC()
208		pi := &model.PaymentIntent{
209			ID:                   fmt.Sprintf("pi_%d", now.UnixNano()),
210			OrgID:                orgID,
211			Amount:               req.Amount,
212			Currency:             req.Currency,
213			Status:               model.PaymentIntentStatusRequiresPayment,
214			HyperswitchPaymentID: hsResp.PaymentID,
215			ClientSecret:         hsResp.ClientSecret,
216			CreatedAt:            now,
217		}
218		return pi, nil
219	}
220	
221	// VerifyWebhookSignature verifies the Hyperswitch webhook HMAC-SHA256 signature.
222	func (s *BillingService) VerifyWebhookSignature(payload []byte, signature string) error {
223		if s.webhookSecret == "" {
224			return nil
225		}
226	
227		mac := hmac.New(sha256.New, []byte(s.webhookSecret))
228		mac.Write(payload)
229		expected := hex.EncodeToString(mac.Sum(nil))
230	
231		if !hmac.Equal([]byte(expected), []byte(signature)) {
232			return apierror.NewUnauthorized("invalid webhook signature")
233		}
234		return nil
235	}
236	
237	// HandleWebhook processes a verified Hyperswitch webhook event.
238	// Events are idempotent: replaying the same event is a no-op.
239	func (s *BillingService) HandleWebhook(ctx context.Context, event model.HyperswitchWebhookPayload) error {
240		paymentID, _ := event.Content["payment_id"].(string)
241		if paymentID == "" {
242			slog.Warn("webhook event missing payment_id", "event_type", event.EventType)
243			return nil
244		}
245	
246		// Extract org_id from metadata if available.
247		orgID := extractOrgIDFromWebhook(event)
248	
249		switch event.EventType {
250		case "payment_succeeded":
251			return s.handlePaymentSucceeded(ctx, paymentID, orgID, event)
252		case "payment_failed":
253			return s.handlePaymentFailed(ctx, paymentID, orgID, event)
254		case "subscription_cancelled":
255			return s.handleSubscriptionCancelled(ctx, paymentID, orgID, event)
256		default:
257			slog.Info("unhandled webhook event type", "event_type", event.EventType)
258			return nil
259		}
260	}
261	
262	func (s *BillingService) handlePaymentSucceeded(ctx context.Context, paymentID, orgID string, event model.HyperswitchWebhookPayload) error {
263		rawPayload, _ := json.Marshal(event)
264	
265		// Use a bypass-RLS transaction for webhook processing since we may not
266		// have org context from the webhook caller.
267		tx, err := s.pool.Begin(ctx)
268		if err != nil {
269			return fmt.Errorf("begin tx: %w", err)
270		}
271		defer tx.Rollback(ctx) //nolint:errcheck
272	
273		// Enable RLS bypass for webhook processing.
274		if _, err := tx.Exec(ctx, "SELECT set_config('app.bypass_rls', 'true', true)"); err != nil {
275			return fmt.Errorf("set bypass_rls: %w", err)
276		}
277	
278		// Idempotency check.
279		isNew, err := s.repo.InsertPaymentEvent(ctx, tx, orgID, event.EventType, paymentID, "succeeded", rawPayload)
280		if err != nil {
281			return fmt.Errorf("insert payment event: %w", err)
282		}
283		if !isNew {
284			slog.Info("duplicate webhook event, skipping", "payment_id", paymentID, "event_type", event.EventType)
285			return tx.Commit(ctx)
286		}
287	
288		// Find subscription by Hyperswitch ID and extend billing period.
289		sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, tx, paymentID)
290		if err != nil {
291			return fmt.Errorf("get subscription by hyperswitch id: %w", err)
292		}
293		if sub != nil {
294			if _, err := s.repo.ExtendSubscriptionPeriod(ctx, tx, paymentID); err != nil {
295				return fmt.Errorf("extend subscription period: %w", err)
296			}
297		}
298	
299		return tx.Commit(ctx)
300	}
301	
302	func (s *BillingService) handlePaymentFailed(ctx context.Context, paymentID, orgID string, event model.HyperswitchWebhookPayload) error {
303		rawPayload, _ := json.Marshal(event)
304	
305		tx, err := s.pool.Begin(ctx)
306		if err != nil {
307			return fmt.Errorf("begin tx: %w", err)
308		}
309		defer tx.Rollback(ctx) //nolint:errcheck
310	
311		if _, err := tx.Exec(ctx, "SELECT set_config('app.bypass_rls', 'true', true)"); err != nil {
312			return fmt.Errorf("set bypass_rls: %w", err)
313		}
314	
315		isNew, err := s.repo.InsertPaymentEvent(ctx, tx, orgID, event.EventType, paymentID, "failed", rawPayload)
316		if err != nil {
317			return fmt.Errorf("insert payment event: %w", err)
318		}
319		if !isNew {
320			return tx.Commit(ctx)
321		}
322	
323		// Mark subscription as past_due — triggers free tier downgrade.
324		sub, err := s.repo.GetSubscriptionByHyperswitchID(ctx, tx, paymentID)
325		if err != nil {
326			return fmt.Errorf("get subscription by hyperswitch id: %w", err)
327		}
328		if sub != nil {
329			if _, err := s.repo.UpdateSubscriptionStatus(ctx, tx, sub.OrgID, sub.ID, model.SubscriptionStatusPastDue); err != nil {
330				return fmt.Errorf("update subscription status: %w", err)
331			}
332		}
333	
334		return tx.Commit(ctx)
335	}
336	
337	func (s *BillingService) handleSubscriptionCancelled(ctx context.Context, paymentID, orgID string, event model.HyperswitchWebhookPayload) error {
