309	// isVoiceNotFound checks if an error indicates a missing record.
310	func isVoiceNotFound(err error) bool {
311		if err == nil {
312			return false
313		}
314		if errors.Is(err, pgx.ErrNoRows) {
315			return true
316		}
317		msg := err.Error()
318		return strings.Contains(msg, "no rows in result set") ||
319			strings.HasSuffix(msg, "not found")
320	}
321	
322	// isTooManyRequests checks if the error is a 429 Too Many Requests error.
323	func isTooManyRequests(err error) bool {
324		if err == nil {
325			return false
326		}
327		var appErr *apierror.AppError
328		if errors.As(err, &appErr) {
329			return appErr.Code == 429
330		}
331		return false
332	}
333	
334	// fnv32a produces a 32-bit FNV-1a hash for advisory lock keys.
335	func fnv32a(s string) uint32 {
336		var h uint32 = 2166136261
337		for i := 0; i < len(s); i++ {
338			h ^= uint32(s[i])
339			h *= 16777619
340		}
341		return h
342	}
